import{j as i,c as t,b as o,ah as n}from"./chunks/framework.Br27zpCu.js";const h=JSON.parse('{"title":"Verifying Native-Web Communication","description":"","frontmatter":{},"headers":[],"relativePath":"bagisto-native/native-integration/android/build-and-run/verifying-native-web-communication.md","filePath":"bagisto-native/native-integration/android/build-and-run/verifying-native-web-communication.md","lastUpdated":1773897321000}'),a={name:"bagisto-native/native-integration/android/build-and-run/verifying-native-web-communication.md"};function r(c,e,l,d,s,u){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="verifying-native-web-communication" tabindex="-1">Verifying Native-Web Communication <a class="header-anchor" href="#verifying-native-web-communication" aria-label="Permalink to &quot;Verifying Native-Web Communication&quot;">​</a></h1><p>Ensuring that the web storefront and the native Android shell are &quot;talking&quot; to each other is critical for bridge functionality.</p><h2 id="_1-verify-bridge-connection" tabindex="-1">1. Verify Bridge Connection <a class="header-anchor" href="#_1-verify-bridge-connection" aria-label="Permalink to &quot;1. Verify Bridge Connection&quot;">​</a></h2><p>When the app loads, open Chrome DevTools on your computer:</p><ul><li>Connect your Android device via USB</li><li>Navigate to <code>chrome://inspect</code> in Chrome</li><li>Find your WebView and click &quot;Inspect&quot;</li></ul><p>In the console, type <code>window.BagistoNative</code> (or your registered bridge namespace).</p><ul><li>If it returns an object, the bridge is successfully initialized.</li></ul><h2 id="_2-check-for-bridge-events" tabindex="-1">2. Check for Bridge Events <a class="header-anchor" href="#_2-check-for-bridge-events" aria-label="Permalink to &quot;2. Check for Bridge Events&quot;">​</a></h2><p>Trigger an action on the web page that is supposed to call a native feature (e.g., clicking an &quot;Alert&quot; button).</p><ul><li>Look for logs in Logcat. If you enabled debug logging, you should see incoming bridge message logs.</li></ul><h2 id="_3-test-a-core-component" tabindex="-1">3. Test a Core Component <a class="header-anchor" href="#_3-test-a-core-component" aria-label="Permalink to &quot;3. Test a Core Component&quot;">​</a></h2><p>The easiest way to verify communication is to use a component like <code>AlertComponent</code>.</p><ol><li>Trigger an alert from your web page.</li><li>Click it in the Android app.</li><li>Observe if the native action (like a toast or alert dialog) is triggered.</li></ol><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>If actions aren&#39;t triggering, verify that the bridge JavaScript is loaded <strong>before</strong> any bridge components are rendered on the page.</p></div>',14)])])}const m=i(a,[["render",r]]);export{h as __pageData,m as default};
